/*
  Learning Hub guide: workspace toolbox blocks by category (colors match flyout strips).
*/

insert into public.lms_learning_guides (
  id,
  title,
  summary,
  card_image_url,
  body_html,
  published,
  sort_order,
  section
)
values (
  'workspace-blocks-reference',
  'Workspace blocks reference',
  'Every toolbox category with the same colors as the flyout—block name, what it does, and how to use it.',
  null,
  $body$<p>This reference matches the <strong>toolbox categories and colors</strong> in the Ollie workspace (left flyout). Each row lists the block type (as in code), what it does, and typical ways to use it. Hat blocks start a script; other blocks stack below them.</p><h2><span style="color:#FFBF00">■</span> Events</h2><p>Events decide <strong>when</strong> a script runs. Every stack needs a hat block at the top.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#FFBF00">■</span> <code>ollie_start</code></td><td>Runs the script once when the program starts (like the green flag).</td><td>Place at the top of a stack. Use one main start script per sprite, or several stacks that all respond to start.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>ollie_event_key_pressed</code></td><td>Runs when the learner presses a chosen key.</td><td>Pick the key from the menu. Use for movement, jumping, or resetting a mini-game.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>ollie_event_stage_clicked</code></td><td>Runs when the stage (background) is clicked.</td><td>Good for “click to begin” or tapping targets on the backdrop.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>ollie_event_backdrop_switches</code></td><td>Runs when the scene switches to a specific backdrop.</td><td>Chain level flow: when “Level 2” backdrop appears, reset positions or show a message.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>ollie_event_broadcast_received</code></td><td>Runs when a named message is received.</td><td>Pair with <code>ollie_broadcast</code> so sprites coordinate (score change, game over, next phase).</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>ollie_broadcast</code></td><td>Sends a named message to all sprites (does not wait).</td><td>Use when listeners should run in parallel. Name messages clearly (e.g. <code>game-over</code>).</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>ollie_broadcast_and_wait</code></td><td>Sends a message and waits until all receiving scripts finish.</td><td>Use when order matters: cutscene finished, then start the next dialog.</td></tr></tbody></table><h2><span style="color:#59C059">■</span> Motion</h2><p>Motion blocks move and turn the <strong>active sprite</strong> on the stage.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#59C059">■</span> <code>ollie_move_forward</code></td><td>Moves the sprite forward in the direction it is facing.</td><td>Inside loops or after turns; use numbers for how far to step.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_turn</code></td><td>Turns the sprite by a number of degrees.</td><td>Positive vs negative angles for left/right feel; combine with move for paths.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_turn_left</code></td><td>Turns the sprite left by a fixed amount from the menu.</td><td>Quick turns for younger learners without typing degrees.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_turn_right</code></td><td>Turns the sprite right by a fixed amount from the menu.</td><td>Pair with forward moves for simple mazes and driving games.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_point_in_direction</code></td><td>Sets the sprite’s heading to a compass angle (0–360).</td><td>0 often points right; 90 up—use for snapping to exact directions.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_point_towards</code></td><td>Points the sprite toward another sprite or target.</td><td>Chase behaviors, aiming projectiles, or following a friend character.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_set_point_toward_aim</code></td><td>Points toward the aim/cursor-style target used in Ollie lessons.</td><td>Use when gameplay uses the aim reticle instead of another sprite.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_go_to_xy</code></td><td>Teleports the sprite to exact x and y coordinates.</td><td>Reset position, snap to grid, or jump between waypoints.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_go_to_target</code></td><td>Teleports the sprite to another sprite’s position.</td><td>Follow the leader, swap places, or spawn at a marker sprite.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_change_x_by</code></td><td>Slides the sprite left/right by adding to x.</td><td>Smooth sideways motion; put in a loop for continuous drift.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_change_y_by</code></td><td>Slides the sprite up/down by adding to y.</td><td>Jump arcs (with waits), gravity-style motion, or bouncing.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_glide_to</code></td><td>Smoothly moves to a position over a duration.</td><td>Animations, sliding doors, tween-style entrances.</td></tr><tr><td><span style="color:#59C059">■</span> <code>ollie_if_on_edge_bounce</code></td><td>If touching the edge of the stage, bounce instead of leaving the screen.</td><td>Keep characters on screen in free-movement games.</td></tr></tbody></table><h2><span style="color:#9966FF">■</span> Looks</h2><p>Looks control what the sprite <strong>says, wears, and how big</strong> it is.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#9966FF">■</span> <code>ollie_say</code></td><td>Shows a speech bubble with fixed text for a duration.</td><td>Dialog, hints, or story beats—stack multiple says in order.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_say_value</code></td><td>Shows a speech bubble with a value (number or text from a block).</td><td>Scores, timers, or variable values the player should read.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_think</code></td><td>Shows a thought bubble instead of speech.</td><td>Jokes, inner monologue, or “Hmm…” moments.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_set_speech_bubble_color</code></td><td>Changes speech/thought bubble styling.</td><td>Match character mood or improve contrast on busy backdrops.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_switch_costume</code></td><td>Switches to a costume chosen from the dropdown.</td><td>Walk cycles, damage states, power-ups—swap art without new sprites.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_next_costume</code></td><td>Advances to the next costume in the list.</td><td>Simple animation by looping next costume with a short wait.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_show</code></td><td>Makes the sprite visible.</td><td>After hide, or to reveal a character at the right story moment.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_hide</code></td><td>Makes the sprite invisible but still running scripts.</td><td>Cutscenes, UI sprites off-stage, or stealth mechanics.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_grow_size</code></td><td>Increases sprite size by a step.</td><td>Power-up growth or emphasis before an action.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_shrink_size</code></td><td>Decreases sprite size by a step.</td><td>Far-away characters or shrinking power-down.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_change_size_by</code></td><td>Adds or subtracts from the current size percentage.</td><td>Fine control compared to grow/shrink.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_set_size_to</code></td><td>Sets size to an exact percentage.</td><td>Normalize size after effects or match two sprites visually.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_switch_scene</code></td><td>Loads a specific backdrop/scene from the menu.</td><td>Levels, rooms, weather—pair with Events on backdrop change.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_next_scene</code></td><td>Advances to the next scene in order.</td><td>Linear tours or slideshow-style stories.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>ollie_play_animation</code></td><td>Plays a built-in animation sequence on the sprite.</td><td>Celebrations, hits, or idle loops tied to art assets.</td></tr></tbody></table><h2><span style="color:#CF63CF">■</span> Sound</h2><p>Play audio clips attached to your project.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#CF63CF">■</span> <code>ollie_play_sound</code></td><td>Starts playing a sound without waiting for it to finish.</td><td>Layered effects or background ambience while motion continues.</td></tr><tr><td><span style="color:#CF63CF">■</span> <code>ollie_play_sound_until_done</code></td><td>Plays a sound and pauses the script until playback ends.</td><td>Short cues where the next action should wait (door slam, success fanfare).</td></tr></tbody></table><h2><span style="color:#5CB1D6">■</span> Sensing</h2><p>Sensing blocks <strong>ask questions</strong> about the world: input, distance, timers, clones.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_touching</code></td><td>Reports whether the sprite is touching another sprite or edge.</td><td>Use inside <code>if</code> or <code>wait until</code> for collisions.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_key_pressed</code></td><td>Reports whether a key is currently held down.</td><td>Smooth movement while key down, or chord checks.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_mouse_down</code></td><td>Reports whether the primary mouse button is down.</td><td>Click-and-hold mechanics or painting-style input.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_is_clone</code></td><td>True when this script is running on a clone instance.</td><td>Different behavior for clones vs the original sprite.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_mouse_x</code></td><td>Horizontal mouse position on the stage.</td><td>Aim helpers, hover parallax, or custom cursors.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_mouse_y</code></td><td>Vertical mouse position on the stage.</td><td>Pair with mouse x for full pointer tracking.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_distance</code></td><td>Distance to another sprite or point.</td><td>Proximity triggers, difficulty scaling, or “get closer” goals.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_timer</code></td><td>Seconds since the timer started (floating value).</td><td>Race modes, speed-run HUD, or cooldown math.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>ollie_sensing_reset_timer</code></td><td>Sets the timer back to zero.</td><td>Start a new lap or phase when an event fires.</td></tr></tbody></table><h2><span style="color:#FFAB19">■</span> Control</h2><p>Control blocks <strong>pause, repeat, and stop</strong> scripts; clone-related blocks live here too.</p><p><em>Note:</em> <code>controls_repeat_ext</code> and <code>controls_whileUntil</code> also appear under <strong>Loops</strong> for convenience.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#FFAB19">■</span> <code>ollie_wait</code></td><td>Pauses the script for a number of seconds.</td><td>Timing between lines of dialog, animation beats, or difficulty pacing.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_wait_until</code></td><td>Pauses until a condition becomes true.</td><td>Wait for collision, key release, or score threshold before continuing.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_repeat</code></td><td>Repeats the enclosed stack a fixed number of times.</td><td>Draw shapes, animate steps, or retry an action N times.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_forever</code></td><td>Repeats the enclosed stack without stopping.</td><td>Game loops—usually ends with <code>ollie_stop</code> or a stop condition inside.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>controls_whileUntil</code></td><td>Repeats while true, or until true, depending on mode.</td><td>Generic Blockly loop; good for “keep going while playing.”</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>controls_repeat_ext</code></td><td>Repeats a stack using a numeric count expression.</td><td>When the count is computed from variables or math blocks.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_stop</code></td><td>Stops scripts (this script, other scripts in sprite, or all—per dropdown).</td><td>Game over, level complete, or emergency reset.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_clone_start</code></td><td>Hat block: runs once for each new clone when it is created.</td><td>Give clones their own behavior (swarm, bullet pattern).</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_create_clone</code></td><td>Creates another instance of this sprite.</td><td>Projectiles, particles, or enemies—pair with clone hat.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>ollie_delete_this_clone</code></td><td>Removes the current clone (not the original sprite).</td><td>Cleanup when a bullet hits a wall or lifetime expires.</td></tr></tbody></table><h2><span style="color:#4C97FF">■</span> Logic</h2><p>Decisions, comparisons, and combining true/false values.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#4C97FF">■</span> <code>controls_if</code></td><td>Runs a stack only if a condition is true; optional else-if branches.</td><td>Score checks, collisions, game states.</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>controls_ifelse</code></td><td>Runs one stack if true, another if false.</td><td>Two-way choices without chaining many plain ifs.</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>logic_compare</code></td><td>Compares two values (=, ≠, &lt;, ≤, &gt;, ≥).</td><td>Plug into <code>if</code> and <code>wait until</code>.</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>logic_operation</code></td><td>AND / OR of two booleans.</td><td>Combine sensing blocks (key down AND touching goal).</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>logic_negate</code></td><td>NOT: flips true/false.</td><td>Invert a condition cleanly.</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>logic_boolean</code></td><td>Constant true or false.</td><td>Defaults or toggles in advanced patterns.</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>logic_null</code></td><td>Represents an empty / null value (advanced).</td><td>Rare—mostly for library-style patterns.</td></tr><tr><td><span style="color:#4C97FF">■</span> <code>logic_ternary</code></td><td>Inline pick: if condition then value A else value B.</td><td>Compact math or text without a full if statement.</td></tr></tbody></table><h2><span style="color:#FFAB19">■</span> Loops</h2><p>Blockly loop blocks; overlap with Control is intentional so learners find them in either place.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#FFAB19">■</span> <code>controls_repeat_ext</code></td><td>Counted repeat using a numeric expression.</td><td>Same block as in Control—use whichever category you open first.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>controls_whileUntil</code></td><td>Loop while or until a condition.</td><td>Matches Control category version.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>controls_for</code></td><td>Loop with a counter variable from start to end by step.</td><td>Grid iteration, draw rows, or index-based logic.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>controls_forEach</code></td><td>Runs once per item in a list.</td><td>Visit every enemy in a list, or process inventory.</td></tr><tr><td><span style="color:#FFAB19">■</span> <code>controls_flow_statements</code></td><td>Break out of a loop or continue to next iteration.</td><td>Exit early when a goal is met; skip invalid items.</td></tr></tbody></table><h2><span style="color:#5CB1D6">■</span> Math</h2><p>Numbers, operators, rounding, randomness, and advanced math helpers.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#5CB1D6">■</span> <code>math_number</code></td><td>A numeric literal.</td><td>Plug into motion, waits, comparisons, and variables.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_arithmetic</code></td><td>Add, subtract, multiply, divide, and power.</td><td>Scores, speeds, and formulas.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_single</code></td><td>Single-argument functions: sqrt, abs, neg, ln, log10, exp, etc.</td><td>Normalize values or smooth difficulty.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_trig</code></td><td>sin, cos, tan, asin, acos, atan in degrees.</td><td>Circular motion and waves.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_constant</code></td><td>Constants such as π and e.</td><td>Geometry and exponentials without memorizing digits.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_number_property</code></td><td>Checks even/odd, whole, positive, prime, divisible.</td><td>Branching rules and validation.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_round</code></td><td>Round, ceil, or floor a value.</td><td>Display scores or snap positions to integers.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_on_list</code></td><td>Sum, min, max, average, median, modes, std dev on a list.</td><td>Stats over a collection of scores or times.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_modulo</code></td><td>Remainder after division.</td><td>Alternating patterns, wrap-around indexes.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_change</code></td><td>Adds a value to a numeric variable.</td><td>Shorthand for incrementing counters.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_constrain</code></td><td>Clamps a value between min and max.</td><td>Keep speed or health in safe bounds.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_random_int</code></td><td>Random integer between two bounds (inclusive).</td><td>Dice rolls, loot, unpredictable motion.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_random_float</code></td><td>Random decimal between 0 and 1 (or configured range per block).</td><td>Jitter, probability checks.</td></tr><tr><td><span style="color:#5CB1D6">■</span> <code>math_atan2</code></td><td>Angle from dy and dx (advanced).</td><td>Point-at-pointer math when built-in point blocks are not enough.</td></tr></tbody></table><h2><span style="color:#9966FF">■</span> Text</h2><p>Build and inspect strings; prompt the player for typed input.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#9966FF">■</span> <code>ollie_ask_number</code></td><td>Prompts the user for a number and returns the value.</td><td>Math games, guesses, or settings chosen by the player.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text</code></td><td>A string literal.</td><td>Labels, names, and messages combined with <code>text_join</code>.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_join</code></td><td>Builds text from multiple pieces.</td><td>Personalized messages with names and scores.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_append</code></td><td>Appends text to a string variable.</td><td>Grow a log or story string over time.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_length</code></td><td>Number of characters in a string.</td><td>Validation or pacing typewriter effects.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_isEmpty</code></td><td>True if the string has no characters.</td><td>Guard before printing optional fields.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_indexOf</code></td><td>Finds first/last position of a substring.</td><td>Parsing simple commands or searching labels.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_charAt</code></td><td>Gets the character at a position.</td><td>Inspect initials or coded strings.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_getSubstring</code></td><td>Extracts part of a string by indices.</td><td>Slice nicknames or drop prefixes.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_changeCase</code></td><td>Upper, lower, or title case.</td><td>Normalize user input for comparisons.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_trim</code></td><td>Removes leading/trailing spaces.</td><td>Clean typed input before logic.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_print</code></td><td>Prints a line of text to the output/console channel.</td><td>Debugging or simple text-only feedback.</td></tr><tr><td><span style="color:#9966FF">■</span> <code>text_prompt_ext</code></td><td>Prompts for text and returns the answer (value block).</td><td>Names, passwords (teach care), or free-form quiz answers.</td></tr></tbody></table><h2><span style="color:#FF661A">■</span> Lists</h2><p>Ordered collections—create, read, update, sort, and split.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#FF661A">■</span> <code>lists_create_with</code></td><td>Builds a list from items (empty or prefilled).</td><td>Start inventories, question banks, or enemy queues.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_repeat</code></td><td>List filled with one value repeated N times.</td><td>Board grids, placeholders, or default scores.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_length</code></td><td>How many items in the list.</td><td>Loop bounds and win conditions (collect all).</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_isEmpty</code></td><td>True if the list has zero items.</td><td>End conditions or “any left?” checks.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_indexOf</code></td><td>Finds index of an item (first/last).</td><td>Lookup before remove or replace.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_getIndex</code></td><td>Reads one item by index (from start/end/random).</td><td>Pick next question, random enemy, or first task.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_setIndex</code></td><td>Writes or inserts at an index.</td><td>Update scoreboard rows or shuffle slots.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_getSublist</code></td><td>Copies a slice of a list.</td><td>Decks, hands, or batched processing.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_split</code></td><td>Splits text into a list by delimiter.</td><td>CSV-style data or tokenizing words.</td></tr><tr><td><span style="color:#FF661A">■</span> <code>lists_sort</code></td><td>Sorts a copy (numeric/text, asc/desc).</td><td>Leaderboards or deterministic processing order.</td></tr></tbody></table><h2><span style="color:#FFBF00">■</span> Color</h2><p>Pick and mix colors for costumes, effects, or logic.</p><table><thead><tr><th>Block</th><th>What it does</th><th>How to use it</th></tr></thead><tbody><tr><td><span style="color:#FFBF00">■</span> <code>colour_picker</code></td><td>Choose a solid color visually.</td><td>Brand colors or art-driven choices.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>colour_random</code></td><td>A random color.</td><td>Confetti, disco, or variety.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>colour_rgb</code></td><td>Build a color from red, green, blue (0–255).</td><td>Fade effects or precise brand RGB.</td></tr><tr><td><span style="color:#FFBF00">■</span> <code>colour_blend</code></td><td>Blend two colors by a ratio.</td><td>Gradients and smooth transitions.</td></tr></tbody></table><h2><span style="color:#FF8C1A">■</span> Variables</h2><p><strong>Flyout blocks</strong> (Blockly generates these): create a variable, then use <em>get</em>, <em>set</em>, and <em>change by</em> blocks. Color matches the Variables strip (<span style="color:#FF8C1A">■</span>).</p><ul><li><strong>Name variables clearly</strong> (<code>score</code>, <code>lives</code>, <code>speed</code>) so stacks stay readable.</li><li><strong>Use “change by”</strong> for counters instead of long set/get math when possible.</li><li><strong>Scope</strong>: default variables are for this sprite; check Blockly’s scope option if you need a variable shared across sprites (when enabled).</li></ul><h2><span style="color:#FF8C1A">■</span> Variables (dynamic)</h2><p>Same family as Variables, with Blockly’s <strong>dynamic variable</strong> list for advanced projects. Strip color matches Variables (<span style="color:#FF8C1A">■</span>).</p><p>Use when projects have many generated names or plugins add variable types—most lessons use the standard Variables flyout first.</p><h2><span style="color:#FF6680">■</span> Functions</h2><p><strong>My Blocks</strong> flyout: <em>define</em> a function with optional parameters, then call it with a matching block. Color matches the Functions strip (<span style="color:#FF6680">■</span>).</p><ul><li><strong>Deduplicate</strong> repeated stacks (draw a door, reset a level).</li><li><strong>Parameters</strong> let one function draw many sizes or colors.</li><li><strong>Naming</strong> like <code>reset game</code> helps kids find their own blocks quickly.</li></ul>$body$,
  true,
  0,
  'Coding Blocks'
)
on conflict (id) do nothing;
